begin;

insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('ad0cb3bd-04bf-5a51-a072-c549488e37fb', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しそうに見ていましたが、作品についての構想では珍しく悩みまくっていました。普段のレッスンでは、オリジナルにしてもアレンジにしても、どんどんやりたいことを口に出して手も動かすタイプなので、もしかしたら「コンテスト」ということで気負ってしまっているかもしれません。 なんとなく作成を始めてみたらイメージがわいてくるかも、ということで、プレイするのが好きというプラットフォーマー系のゲームを作成しようというところで時間切れでした。', '自分のゲームイメージを形にするスキルが足りていないとしょんぼりしていたので、次回はプラットフォーマーの教材を用意して軌道に乗せてから、ゆうかちゃんの得意なアレンジを加えてストーリーを考える余裕をもたせてやりたいです。', '時間帯: その他
タイピング: 問題なくできています
盛り上がり: ゆうかちゃんには珍しく、考え込む時間が多かった回となりましたが、背景やスプライトのイメージを考え始めると少しずつ乗り気になってきたようでした。'),
  ('103dad47-701a-5364-8bd6-1ae29bd6ec89', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は楽しそうに見ていて、ところどころツッコミや意見を入れては場をもりあげてくれました。 前回から作成している楽器演奏の作品を作成してみてから、コンテストに使うかどうか決めたかったようで、熱心に楽器演奏に使うキーを決めたりしながら、見た目も音も楽しい作品に仕上げていました。 コスチュームの細かい編集や使用するキーの位置などもよく検討して、触って楽しい作品にできていたと思います。', 'コンテスト参加作品の見通しをたてる', '盛り上がり: 設定に妥協しないけいとくんの辛抱強さがよく発揮されていて、作品を触る人がいろいろ工夫して演奏できるようにがんばっていました。けいとくんの作品を使って、けいとくんが弾いていなかった「かえるの歌」の輪唱バージョンを弾くと、とても喜んで、一人合奏ができるようにキーの位置を改善したりしてくれました。'),
  ('95aa82bc-7797-550e-9cb8-6e8c80b004e9', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画は面白がって見ていましたが、前回作成中だった騎士vsドラゴンが気になっていたようで、動画視聴後しばらくそちらをいじっていました。 途中から、キャラクターを変えて対戦ゲームにする！と言い出し、自力で作成を始めていました。アレンジ大賞の中級対戦ゲームが面白かったようで、自分で作ってみたいようでした。ゲーム作成のモチベーションは上がっているので、とりあえず作成を進めてからストーリーを考えてもよいかもしれません。', null, '盛り上がり: 対戦ゲームへのこだわりがあるらしく、一生懸命考えたり質問をしたりしながら、自分の知識を総動員して頑張っていました。 今は盛り上がって作成している段階なので、水を差さずに作成させていきたいところです。'),
  ('c799c822-3c0e-588c-94e6-4c123470873d', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画はツッコミを入れたりしながらも熱心に見ていました。 何が大事かはわかったようで、「はいはい」と返事をしつつもそれなりに考えている様子が見られました。 作りたいものはすぐに思いついたようで、スプライトを自作したりしながら、かなりのスピードで作成を進めていました。', null, '盛り上がり: 自分の言葉とコードで作成することの重要性がわかったのか、アレンジ大賞で自信がついたのか、他のゲームで遊んではコードを拝借していた昨年とは違い、それなりに楽しそうに自分で作成できていました。'),
  ('a707524a-91a4-58ae-b7ad-f0ed6d50562a', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '16:30:00', null, '振替 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画をとても熱心に見ていて、かなり感銘も受けたように見えました。 ひろとくんと同じ学校の同学年なことがわかって一気に仲良くなっていました。ゲーム作成への熱意の面でも気が合ったのか、お互いに作りたい仕様などを話しては意見を出し合ったりと、口も手もとても熱心に動かしていました。 やりたいことがありすぎて暴走して全体像が見えなくなることがあるため、最初に計画を立てることを勧めたところ、高尾山で冒険をするたぬきのストーリーを作りたいと言って、高尾山の名物や生き物などをWebで調べながら、ストーリーの流れ、アイテム、登場キャラクターなどの計画を丁寧に紙に書きだしていました。', null, '盛り上がり: コンテストを楽しみにしていただけあって、動画を見ながらもアイディアがわくのを抑えきれないようにコメントを入れていました。 ひろとくんと最後まで盛り上がりながら、しっかりと設定を書き出して満足そうにしていました。
備考: 新しい自分のPCを持ってきていて、嬉しそうでした。'),
  ('1d5d54ec-74b0-52f1-b5dd-67d7531883bc', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', '動画をとても面白そうに見ていました。かんたくんと積極的に意見を出し合ったりしていました。 作品の全体像を考えるということもよく理解していて、どんなゲームにしたいのか、設定やキャラクターの仕様などを紙に熱心に書き込んでいました。頭の中で、かなりのイメージがわいているようでした。', null, '盛り上がり: かんたくんと同じ学校の同学年だったことがわかって、とても楽しそうに話しながら計画をたてていました。'),
  ('88cf28b8-3b51-5a68-af1e-56505336a514', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-22', '17:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える →昨年度の親子プログラミング大会優秀作品の動画を見て、工夫されているところはどこかを見つけて、自分にできることを考える', 'コンテストの動画は興味深そうに見てコメントもしていましたが、参加を勧めてみると即座に「却下！」と言っていました。ゲームはやりたいけど作りたいわけではない、おもしろいゲームがあったら、自分で時間をかけて作るのではなくて、すぐに遊びたいんだ、と力説していました。 それでも柊くんと、にゃんこ大戦争についてしゃべりだしたら少し興味が出たのか、BGMの視聴サイトで1曲ずつ丁寧に聴いて、ゲームに使えそうな曲タイトルをきれいに書きだしていました。 選んだ曲を使って、狸大戦争にしたら面白そう、と言っていましたが、先生から作成のプレッシャーをかけられることは嫌そうでした。', null, 'タイピング: タイピング中に手首がトラックパッドに触れてしまうのか、何度もウィンドウが切り替わって少しイライラしていました。
盛り上がり: 曲を選んでどんな場面に使えるのかを考えているときは、とても楽しそうでした。 こちらから勧めすぎたりしなければ、自分から何かをしようとする姿勢を見せてくれました。'),
  ('e771240d-e533-5e3c-b4ed-27a77e6851b4', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-22', '18:40:00', null, '休み（未対象）', null, null, null),
  ('8f213c9b-d6ad-5a0f-8a2d-0fadc7dc2fa2', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-22', '17:30:00', null, '通常 / 大会準備', '去年のコンテストの受賞作品を見ました。作品のいろいろなところに注目ができていて素晴らしかったです。ストーリーに関してはあまりすぐに気が付けていませんでした。蚕や猫を例にとって説明すると「なるほど～」というようなリアクションでした。 アクションゲームにするそうです。何かから守るゲームを作成するそうですが、「何から」「何を」守るのかはまだ未定なようです。今日はホーム画面に使えるスクリプトを作成していました。アイデアはたくさん出てきそうなので、来週以降楽しみです！', null, 'タイピング: 準2級が出て喜んでいました！'),
  ('c085c851-82be-5083-8147-4e9f2ea788fd', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-22', '16:30:00', null, '通常 / 大会への準備！', '去年の受賞作品のムービーを見ました。 その後、自分の作っていた作品のバグを一緒に確認しました。「〇秒まつ」をいれるとうまくプログラムが動かない問題が発生して、かなり悩んでいました。同じ内容を別の文法（違うブロック）を使って試してみるようにアドバイスをしました。「背景が～になったら」の代わりに「～まで待つ」を使って解決しました。ウミガメのプログラムも同様にひとつずつ整理して考えました。完成後も、同じプログラムを書いているのにうまく動かなかったり動いたりが続き、かなり苦労しました。', null, '盛り上がり: プログラムの内容に大きな間違いはないので、「うまく動かない」ことが本人に大きなストレスになっているように思います。しっかりサポートしていきたいです。。'),
  ('8188ebcd-eea1-5271-836c-6b3afbab3dcc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-20', null, null, '通常 / 変数を使ってスコアをつける、ゲームクリアの作成', '「今日は何をやる予定だったか」たずねたところ、きちんと覚えていて、作品を動かしながら説明してくれました。 のあくんと学校で顔見知りになったと言っていたので、先輩意識を利用させてもらいました。「今日はのあくんも追跡ゲームをやるから」と伝えたら、とても嬉しそうに自分のPCと並べて座り、上下左右に動かすスプライトの説明をして、座標を使って動かすんだよ、と丁寧に教えてくれました。 のあくんに教えたり、自分の課題を進めたりと忙しそうでしたが、最後までとても集中して、こちらの説明もよく聴き、自分でも考えながら作成できていました。 スコアの変数は意味がわかりやすかったようで、どのタイミングでスコアを増やしたいかという質問だけで、正しい位置にブロックを入れることができました。 初期値のブロックは、「最初に入れる」ことはわかったものの、最初は「ずっと」の中に入れていて、得点がおかしいと考えこんでいましたが、「どうしてスコアが毎回すぐに0にもどるのかな？」とのヒントで解決できました。 スコアが完成してからゲームをプレイして、「ゲームがいつまでも終わらないのはおかしい」と自分から「ゲームクリアを作った方がいいんじゃないか」と申し出てきました。 演算式と「まで待つ」のブロックは、「こんなのがあるのか」と面白がってくれました。', null, '時間帯: その他
タイピング: 大文字のLが表示されたときに毎回迷っていましたが、最後の方にはだいぶ慣れてきたようでした。
盛り上がり: のあくんに先輩として接することで、集中力、思考力が飛躍的に伸びていました！ こうしろうくん自身も、説明を口に出すことで頭の中が整理できたようで、納得するのも早く、何よりも最後まで楽しそうに取り組んでいました。'),
  ('2aa84cb6-48da-5bc3-81e3-6dce8d48b1c6', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-19', '16:30:00', null, '通常 / 作品にオリジナル性、ストーリー性を付け加える 作品に使えそうなスキルの確認', '前半は八王子親子プログラミング大会の昨年の決勝大会動画を視聴しました。 動画は熱心に見ていて、興味も持ったようですが、帰り際の本人の話によると、コンテストについてはイマイチ理解しきれなかった可能性もあり…そのあたりのイメージは、低学年には経験がないとつかみづらいかもしれませんが、たくやくん自身の作品を作りたいという意欲はきちんとあるので、そこを伸ばす方向でコンテスト提出にもっていきたいところです。 年齢の割にはしっかりしている子ですが、全体を意識することは難しい面もあり、作成をしていても、コスチュームの一部分や一つの動きにこだわりすぎて、何を作っていたのかわからなくなってしまうことがあります。文章を書くことはできる子なので、次回は設計図のようなものを書かせてみてもよいかもしれません。', '作りたいものを整理して設計図を書き、作成していく手順を先生と一緒に考える', '盛り上がり: コンテストの動画はとても面白かったようで、良い刺激にもなったようでした。'),
  ('6f1f3cac-bce6-5cd2-ad4c-0a7905ce7337', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-20', null, null, '通常 / 親子大会の作品作り', 'みんなと一緒に前回の受賞作を見たあと、アイデア出しから始めました。RPG系の対戦ゲームを作ることにしました。森や海などのステージごとに違うボスを用意するそうです。また、剣の種類を変えることでパワーアップをしたり、プレイヤーのレベルもつけたりする計画を立てています。', null, '時間帯: その他
盛り上がり: 積極的に取り組んでいて楽しんでいたと思います。'),
  ('470434c6-264a-5b22-a49a-03b900fb61a8', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-20', null, null, '通常 / 八王子プログラミング親子大会', 'プログラミングのコンセプトを全部含んだ作品を作ると言って、気合をいれて作業に取り組んでいました。 どんな物を作るのと聞くとそれは言えないと、断固拒否されたので完成したら見せてくれるようにお願いしときました。 話を聞いている感じだと彼の中では、しっかりとした設計図が出来上がってるように思いました。なので、何もなく順調に進んでいけばクオリティーの高い作品が出来上がるように思います。 本日も作業をしっかりしていたので、特に問題ないかなと思います。', '制作の続き', '時間帯: その他
タイピング: なし
盛り上がり: 葉琉くんが分からないというコードの質問に、親身になって一緒に考える姿が見受けられました。遠くから見ていてとても仲良く一緒に作業を取り組んでいました。 今後も助け合いながら、作業に取り組んでくればどんどん成長していくことだと思います。'),
  ('51b1fd66-8232-5c3c-a93a-a2a41a03055f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-20', null, null, '通常 / 親子大会の作品作り', 'みんなと一緒に前回の受賞作を見たあとアイデア出しから始めました。作るゲームは、そうたくんと同じRPG系の対戦ゲームに決めました。全体のイメージを紙に書いてみようと促すと、スラボーが主人公で、途中で仲間を集めながら魔法使いなどの敵を倒していく流れに決まりました。今日できた作業はスプライトを用意してコスチュームを自分で変えるくらいだったので、次回以降具体的な動きに入っていきたいです。', null, '時間帯: その他
盛り上がり: 最初はモチベーションがあまりなくゲームを遊んでしまったのですが、隣のそうたくんが製作を始めているのを見てあおしくんもだんだんやる気を出してきました。'),
  ('6a0715c9-8864-5608-808e-7df01163647d', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-20', null, null, '通常 / 八王子プログラミン親子大会の制作', 'プログラミング大会のコンセプトを、しっかり決めて制作されていました。 制作内容は、「部屋を掃除するゲーム」を作るという事で頑張って素材集めをされていました。 そざい集めには、フォントを制作出来るサイトを使って制作されていました。 動きのプログラムで分からない事は、大貴くんに聞いて解決している姿が見受けられました。 とても、仲良く一緒に作業をされていたのでとても良い感じでした。', '制作の続き', '時間帯: その他
タイピング: なし
盛り上がり: 大貴くんと仲良く一緒に作業をされていました。 また、コードの失敗を何度も繰り返しながら間違えを見つけて、解決する姿がとてもワクワクしていました。'),
  ('c25a3593-c6b5-572c-9b91-72c645594744', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-15', '17:30:00', null, '振替 / 回転による反射、マウスのx座標', 'テキストに沿って進めるというよりは「次はどの部分を作ろうか？」と問いかけながら進めていきました。パドルの動きでマウスのx座標を使うのが難しかったようで、少し時間をかけて考えていました。シンプルに考えるため、x座標とy座標で別々に考えてみることを促しました。また、壁でボールを反射させるときは「端に触れたら跳ね返る」がすぐに思い浮かんでいましたが、パドルでボールを反射させるときはどうすればいいのか見当がついていない様子でした。そこで、反射する前後のボールの軌道を絵に描いて見せると、角度が変わっていることに気づけました。最後は若干時間がオーバーしてしまったのですが、続けたいと言って完成までたどり着きました。', null, 'タイピング: 真剣にやっていました
盛り上がり: 自分のペースで考えることを楽しんでいると思います。'),
  ('4ccd16b7-85a6-5ddf-a1fb-f318fd011986', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, '4fb853b8-7d59-5565-9d96-060872e780d1', '2023-05-13', null, null, '通常 / 左右上下の動きをマスター', '追跡ゲームを最初にやってもらう。 鋼志郎君は、はじめはこのゲーム制作に乗り気ではなさそうで。クリオネのスプライトをずっといじっていたので。追跡ゲームのロボットをクリオネにして作ろうと提案。追っかけるものは「クリスタル」に決定。 講師は、最初にゲームの全体を子どもに考えさせるようにお願いします。 「これって、ロボットはどうやると動いた？」 「ロボットが星にあたると、どうなった？」 ↑↑要は、意図的に細分化思考で考えさせる。 最初の矢印キーで上下左右に動かす＝X座標とY座標の理解までできました。 ただ、次回は忘れてしまっている可能性も高いので。２年生だし。 帰りがけに、「今日はX座標とY座標をやったね。来週はゲームでよくでてくるスコアをつける方法をやろうね」と伝えています。なので、「先週、X座標よY座標やったの覚えてる？」「今週はスコア作ろうねって約束したよね～」と話をしてあげてください。 落ち着きがあまりない子なので、毎週一つを意識的に取り組んでもらい、翌週必ず復習して積み上がっている経験をして欲しいです。よろしくお願いします。', '今週は「スコア」というゲーム制作スキルを作れるようにしよう！とモチベアップさせてください。', '時間帯: その他
盛り上がり: ゲームのキャラクターにクリオネを使おうと提案した時は、嬉しそうでした。クリオネが追いかけるものを何にするのか、選ぶのが楽しそうでした。
備考: ★相当の負けず嫌いな子だということ。教室内で対戦ゲームして負けると、そのままふてくされがひどくなるので注意です。 ★お母様が、割と内容や進度を気にされているので、特に先に記載したように毎週一つのテーマを持って積みあがるようにしてください。'),
  ('e71685db-0686-5e07-86f5-33fde7e71a95', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '18:40:00', null, '通常 / 親子プログラミング大会準備 -ストーリーなど', '去年の大会の決勝に残った作品のムービーを見ました。比較的真剣に見ていました。自分でアイデアが出てこなかったので、カードを使ってアイデア出しをしました。天秤、葉、時計などが選ばれました。対戦ゲームのようなものを作るそうです。剣の動きやアルゴンの動き、天秤などの素材の色などをこだわりました。今ままで学習したことをしっかり使えていて良かったです。来週から楽しみです！', null, 'タイピング: 腕試しのふつうに挑戦しました。とてもよく集中していました。
盛り上がり: 時間いっぱい集中できていました！'),
  ('d44257fd-659c-5dd8-a83e-04f17b4dc196', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '17:30:00', null, '通常 / 親子プログラミング大会準備 --ストーリーなど', '本人はプログラミング大会に出品したくない様子でした。スプライトも自分のオリジナルではなく、既存のものを使うことになりました。 ホラーゲームを作りたいそうです。場所が変わったり、充電が必要なライトで照らしたりして点検するゲームだそうです。今日はどちらかというと、他の作品を見たり壁紙を探したりしていました。来週までにより詳しい内容を考えてくるようにお願いしました。', null, 'タイピング: 腕試しのふつうに挑戦しました。正解率も高かったです。'),
  ('4968e634-aefc-5b04-9245-c835732ca84a', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-19', '17:30:00', null, '通常 / カブトムシを動かす 条件分岐での上下左右の動き習得を目指して、キーで動かすイライラ迷路でもよいかも', '前回プログラムした「全てを止める」が、「ーキーを押したとき」のプログラムがあるためうまく動いておらずかなり不満げだったので、変更方法を伝えました。一度実演して見せると、左矢印キーを押したときのプログラムは何とか自分でできましたが、ジャンプのプログラムを変更するのは難しかったようです。自分でも「難しい」ということに気が付けていました。 一度習得した内容がなかなか覚えられていないようです。繰り返し取り組む必要があると感じました。', 'こどもタイピングをすっごくやりたいそうです！', 'タイピング: 腕だめしの簡単に挑戦してもらいました。正答率は66%ほどでした。本人は難しいに挑戦したかったみたいです。こどもタイピングにも興味があるようなので、次回から挑戦したい様子でした。
盛り上がり: 去年のプログラミング大会の決勝の作品のムービーを一緒に見ました。その後「プログラミングやる！！」とモチベーションが上がっていたのでとてもびっくりました！！！'),
  ('1ac7214e-4240-56ab-9f21-6a20fda0ea9f', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-19', '18:40:00', null, '休み（未対象）', null, null, '備考: 本人が自宅電話に出ました。夕食中とのことでお休みです。'),
  ('293288bd-981a-5ffb-bf78-2271362f8f56', '13bd73d0-f535-5291-8362-6712e5cd7384', null, null, '2023-05-19', '16:30:00', null, '休み（振替対象）', null, null, '備考: 5/22 16:30に振替'),
  ('4f96b489-22e9-5e26-85ac-c140645f112d', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-05-19', '16:30:00', null, '休み（未対象）', null, null, null),
  ('486ab480-7e63-52fe-8075-8b4a53419c66', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-18', '17:30:00', null, '通常 / アルスパークの使い方を復習しよう', '前回からほぼ1か月空いてしまったので、全体的なアルスパークの復習をしながら、ゾンビを倒せ１を作っていきました。基本的な向きやざほひょうの見方、スプライトの探し方はわかっていました。そして、過去何度かつくった「上下左右に動く」の作成は前回よりコードの選びが速くなっていて、xyの違いも１テンポおいて正しく選ぶことができました。成長しています。次に、ゾンビに動き方を動画を見ながら使い方の木なるポイントを聞きながらコードを学んでいきました。新たに間違えて別のスプライトに作ってしまったときに、バックパックに使って移動する来tも学びました。', 'ゾンビを倒せの続き', 'タイピング: なかなかUが見つけられていませんでした
盛り上がり: 久しぶりだったから着てすぐ自由に作り始めました。'),
  ('87575b8a-e6a7-542f-8614-dcefd389efe7', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / コンテストの計画、小技系から興味のあるものを習得', '承太郎君と一緒に、コンテストに向けての説明をしました。アレンジ大賞のコードが評価されたことで、昨年のように流用したコードで凝ったものを作成するより、自力でバグがないように、オリジナリティのある作品を作った方が良いということも、とても素直に納得していました。 昨年度の大会の動画を見ながら、色々と考えていたようでした。 後半は、自分で使えるコードを増やすという目的で、小技の中から「体力ゲージ」を選んで自主的に学習していました。', null, 'タイピング: 相変わらずのスピードで、3回ほどチャレンジしていました
盛り上がり: 昨年の動画を熱心に見たり、こちらの話をよく聞いて質問を返したりと、コンテストに向けてのやる気が見えました！'),
  ('74233f5a-f704-50a7-96bf-b740012682a3', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / ストーリー性を考える コンテストの動画を視聴して計画をたてる', '前半は、完成した自作を公開した、と言って2つの作品を見せてくれました。文字の動かし方については、クローンと座標の変化で上手にできていました。Scratchでは「秒待つ」よりも「タイマー」の方が時間が正確なので、あえてタイマーの数値を利用して動かしているところがポイントだと説明してくれました。 今後のコンテストについて、承太郎君に強化してほしいこと、留意してほしいことをゆき先生と一緒に伝えました。納得はしたようですが、まだ、作りたいものとの一致がしないようで、文字PVの修正などをしながら、作品に使えそうなコードやイメージなどを探していました。', null, 'タイピング: 久しぶりにタイピングをした、と言いながらも、それなりに良い結果が出ていました
盛り上がり: 文字PVに関してはかなり作成に慣れてきたようで、嬉しそうにいくつも解説をしながら見せてくれました。 Scratchでの共同作成を通して、クリエイターとしての意識が強くなっているように見えました。'),
  ('bc1a0f25-4fd0-50f0-be19-4933c15a7a8e', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-18', '16:30:00', null, '通常 / コードの並列作りを理解しよう', '先週は変数の計算でだいぶん頭を悩ませていたので、コードの作り方を意識させるをメインしたアルくんの冒険１を作っていきました。最初、遊んだ時に斜めジャンプを気づけていたので、それを作れるようになるよう目標立て進められました。左右の動きはなにも迷うことなく作れていました。ジャンプはy座標が増減するする動きということは理解していましたが、コードに表すと、動画で上がる動き見せて作ったが、下がる動きは少し迷うっていました。上がる下がるは逆の動きなので、上がる動きは上に向いてることからその逆と連想しやすいように誘導しました。そして、下がる動きを上がるの繰り返しの中に入れて試していたため、ジェスチャっちゃーで今の状態を示してあげたら、可笑しいことに気づき、上がりきってから下がることに作り替えることができました。 その後、ゴール演出も自分好みのものに作り替えて、完成することはできました。あと、斜めジャンプできるときとできないときのコードの違いが見せられていないので次回初めに見せられたらいいと負います。', null, 'タイピング: 皆レベルアップしてきてつよくなってきました
盛り上がり: ポケモンのはまり方がすごかった。'),
  ('4dc7bc5f-9fc6-559b-8d89-38c1f8ccaf9b', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '17:30:00', null, '通常 / 脱出系ゲームの作成、もし興味を示してくれたら、「変数で場面を変える」', '今日はスマホで北朝鮮のニュースを見ることにハマっていたようで、テポドン発射のショートアニメを作成していました。スプライトや背景の動き、コスチュームの表情の切り替え方、大きさを活かした遠近法など、内容が物騒なのはともかく、よく工夫された作品ができていたと思います。 残念ながら完成したら作品を削除してしまい、その後はひたすら「ずっと」ブロックを並べたりして遊びに入ってしまいました。 帰り際に、最初に作った作品を褒めたところ、「仕方ないからまた考えて作ってあげる」とのことでした。 ストーリーを表現するための工夫については着実に進歩しています。', null, '盛り上がり: 表現力がついてきていて、そこを褒めると謙遜しながらも嬉しそうにしてくれていました。'),
  ('0e2126e0-d032-5ed9-b4c7-ad1a8e661b77', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-18', '16:30:00', null, '通常 / 乱数の理解を深める→座標を乱数で指定する、乱数を使って虫の回転方向をランダムにする', '前回、チーズがネズミに触れたらどこかの場所へ行く、と作成していたところ、今日の初回のプレイでちょうどチーズが迷路の後ろに入り込んでしまい触れられなくなったので、「どこかの場所へいく」と座標を乱数で指定することの違いと後者のメリットを説明しました。りょうやくんもしっかり納得して、自分でスプライトを動かして座標の数値を調べながら作成できていました。 ランダムな動きをする敵については、敵の大きさにこだわりがあって迷路内を動かすことができずに「どこかの場所へいく」で動かしていましたが、スコアの変数については、スプライトに触れるときの主体のスプライトがどちらかまでしっかり意識をして作成できていました。 終盤では、敵のコスチュームの編集や、ウロウロさせる動きが面白くなってしまったようで、回転方向をランダムにするところまでは進めなかったため、お手本の虫の動きを見せて、次回はこの動きをする敵を作ろうと予告しました。', null, 'タイピング: ポケモンタイピングで良い結果が出て喜んでいました
盛り上がり: 自分がゲーム内で作りたいことと学習内容が一致すると、とても熱心に考えて説明もよく聞いてくれます。座標に乱数を使う意味も面白がってくれました。 自分が納得するゲームを作りたい、という意識が強いため、脱線することもありますが、りょうやくんなりに考えて作成を楽しんでいるようなので、一つ一つの単元を習得する意味を納得してもらいながら進めていきたいと思います。'),
  ('c40810e4-6686-5fdd-9793-72e40e869d70', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-16', '17:30:00', null, '通常 / ゲームで使えるスキルの習得', '昨年度の親子大会入賞者がお友達だとかで、どんな作品が入賞したのかとても気にして見ていました。 今日はYouTubeで見つけたジャンプを自分で作ってみたいとのことで、ジャンプの速さを変数にしたジャンプを一生懸命作成していました。 当初はジャンプしたままになってしまうバグがありましたが、自力でコードを見直して解決できていました。 複数のスプライトのコスチュームをうまく組み合わせて編集して新しいスプライトを作成したり、ジャンプの種類を増やしてみたりとみずきくんなりの工夫が見られました。', 'コンテストに向けてストーリーの大切さを説明し、モチベーションをあげていきたいところです。', 'タイピング: 軽く1度ながしていました
盛り上がり: 最終的に記憶通りのジャンプができたようで満足そうでした。 バグがなかなか直せなかった時も、途中で投げ出したりゲームに逃げたりせずに集中することができていました。'),
  ('d58358f0-5476-5d2b-b54f-a36641430621', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-16', '17:30:00', null, '通常 / ピンポンゲームから知識を得よう', '今日はピンポンゲームを通して様々な知識を学んでもらいました。このゲームは、「端に触れたら跳ね返る」や「マウスのx座標」など知らないとつかえないブロックなどが多くあるので、それをつかうために1つ前の質問を与えて挙げて、新しいブロックがどうゆうものなのかわかるように進めていきました。受けごたえもよく理解はできていると思います。随所に、音のアレンジを加えると、ボールを跳ね返す音や赤線に触れた時の音の選びがセンスが良くてやっていて気持ちいです。そして、スコアの付け方やゲームクリアの仕方などは迷わずに作れていたので、その辺の知識は蓄えられています。最後にスコア10になった時、歯車を回す演出があえて大きくすることで見ごたえのあるものなっていました。', null, 'タイピング: 頑張っています
盛り上がり: 時間が過ぎても完成までして達成感を得ていました。'),
  ('e2a52e71-eb62-5d3e-bf4f-59cc656d839f', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '17:30:00', null, '通常 / ジャンプゲームアレンジ', '前回作った作品のプログラムを一緒に確認しました。なんとなく思い出したようです。アレンジの内容があまり思いつかなかったようなので、ゲームの終わりの設定を提案しました。「スコアが10点になったら終わり」のプログラムを忘れてしまっている様子でした。条件分岐のブロックを使うこと、等号のブロックを活用することを説明しました。 またテニスボールの動かし方が気に入っていなかったようなので、乱数を使って工夫することを提案しました。 やったことをあまり覚えていないようなのでもっと復習が必要かもしれません。最後にキャッチゲームを遊び、内容を確認してもらいました。', null, 'タイピング: 集中して取り組めていました。みたことのないステージまで進んでいてびっくりしました！
盛り上がり: しっかりコミュニケーションがとれました！'),
  ('5ffa3bc9-40b3-5475-9045-fa8295c64121', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '17:30:00', null, '通常 / ジャンプ-変数の使い方', '歩く速さがだんだん上がるプログラムを作ってもらいました。テキストをしっかり読み、スムーズに取り組めていました。変数の使い方もよくわかっている印象でした。 次に歩くのではなくジャンプにその変数の使い方を応用し、速度の変化するジャンプを作ってもらいました。ジャンプのおわりとして地面を把握するために色の判定をつけたり、本当のゲームっぽくカウントダウンを付け加えたりしてアレンジを加えました。うまくジャンプさせるために「地面に埋まる」という現象への対応を熟考しました。その現象を改善するために、ジャンプするタイミングのプログラムを検討しました。 自分なりに改善策を考え、対応できていたので素晴らしかったです。変数を使ったジャンプのプログラムはしっかり理解できていました。', null, 'タイピング: 正答率もとても高く、集中して取り組めていました。'),
  ('50ae7a37-882d-5494-b0f7-7674fb7cdd97', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '16:30:00', null, '通常 / 初回。教室になれる', 'とても前向きに取り組めていました。動き、音、色を変えるなど、基本的な動きを確認できました。積極的にいろいろなブロックを動かして試せていました。座標の話も少しかみ砕いて説明しました。理解できているかは微妙です。自分の作品に対して世界観をとても大切にしている様子でした。次回は名前を動かすことを伝えました！', '名前を動かす', 'タイピング: うでだめしの簡単に挑戦しました。難易度はちょうどよさそうでした。
盛り上がり: とても楽しく取り組めていました！'),
  ('3bc9b382-33c5-5153-ad1c-f46089aee16b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-16', '16:30:00', null, '振替 / 単元別演習F 条件分岐', '一番最初に敵から逃げるプログラムを自力で仕上げていました。文章をあまりきちんと読めていなかったようなので、自分で作っているうちに敵と逃げるスプライトを混同してしました。いっしょに話して整理して進めるとうまくプログラムを作ることができました。 敵と逃げるスプライトがぶつかったときに話す言葉を工夫していました！ 次に、自分で作品を作り始めました。騎士が剣を散らしてドラゴンを攻撃するようです。作りたいイメージとある程度のスキルもあるので、順序立てて考えられるようにするとスムーズに作品作成ができると感じました。', null, 'タイピング: とても集中して取り組めていました。正解率も高かったです。
盛り上がり: 積極的に取り組めていました！休憩もほぼなかったです！すごい！'),
  ('287da3f8-4341-52be-9df8-c8f1f07146a7', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-05-16', '16:30:00', null, '振替 / 定義の使い方を学ぼう', 'とらくんにはアルくんの冒険にて、定義を使ってみてコードの見やすさを重視して作ってもらいました。基本は見ないで作り、こだわってほしいところはこちらから指示をするような形で作っていきました。作り上げていき、1か所違うところでバグが発生したとき、どこが違うか探してほしいにもかかわらず、すぐに左に捨ててしまう癖を少し気になりました。発想はいいのに少し無駄になる可能性があるので、立ち止まることも大切にしてもらいたいです。早早と作りあがったので、ジャンプを放物ジャンプに変えてもらいました。それで、敵も動きが少ししかなかったので、アレンジをしてもらったら、大量のクローンをで雪崩のように流れ、見ごたえのあるものができました。', null, 'タイピング: 5分間集中して途切れずにできていました。
盛り上がり: 最終的にできたものは周りのみんなが楽しがってもらえていました。'),
  ('4b2ecf83-d631-5fd1-bba0-2846c1ef8168', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-16', '16:30:00', null, '通常 / 条件分岐と演算式の活用を考える', '先週に引き続き、結果発表の画面を作成しました。 太鼓の3種類の判定を得点にするイメージがわかなかったようなので、さらちゃんが盛り上がっているタイピングの得点はどう出ているのかなどもあわせて考えながら、演算式を組み立てていきました。 演算式が完成するまでは「一人だとわからない」という反応でしたが、得点が出せるようになると、その先の条件分岐による結果発表の切り替えは自力で作成でき、満足そうにしていました。', null, 'タイピング: 学校で出した最高記録を更新できたと喜んでいました
盛り上がり: イメージしていた結果発表ができたようで、達成感も味わえたようでした。'),
  ('3b2d05ce-0c80-539d-be47-7c496de1c3f7', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-15', '16:30:00', null, '通常 / コンテストに使える小技を身に着ける', 'コンテストの作品作りに役立つかもしれない小技に取り組みました。定義を使わない簡潔な書き方で作りました。 最初に、被弾したらHPの変数を減らすコードを書きました。その際に、変数が重複して減ってしまわないようにしてもらいました。レースゲームでも使った「～ではないまで待つ」を使えばよいので、レースゲームの内容を思い出してもらいました。 次にボールを繰り返し発射する動きを作りましたが、想定よりも詰まってしまいました。そのとき口頭で細分化をすると少しずつ流れが見えてきました。 最後に、本題であるHPゲージを作成しました。まずは、透明なスプライトを動かすことでペンで線を書き、それがゲージになるという原理を説明しました。そして、ゲージの右端と左端の場所はどこかなと問いかけると、座標を動かしてゲージを完成させることができました。', null, 'タイピング: タイピング練習は久々でしたがうまくできていました。'),
  ('97479275-e384-5eb8-b6d3-1975a04ec551', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '17:30:00', null, '通常 / 小技、体力ゲージ wkhttps://app.arspark.jp/projects/32936/editor この体力ゲージの部分をペンツールを使ってどう表現するのか？を最初にやってみる 座標で動くのと同じなんだというのが分かれば、この部分はえにしくんのとっては楽しいものになるかな？と その後に自由に作成していけば', '最初は色々と右往左往して違うゲームをやったりしていましたが、最終的にはゲージのプログラミングをしてくれました。 ただしゲージを書くというよりかは、ボールがあったっている時間が長いためにバグになってしまっている部分があるよ〜と話をふり、昔やっていたことを思い出してもらいました。 1秒待つ〜というコードを増やせばできることや、〜ではないまで待つというコードが増えることでバグ解消に繋がること、誘導しながらでもきちんと思い出しならがらやってくれました。 最後はあるくんと猫のHPのゲージを作ってみました。', null, 'タイピング: 以前と比べてはるかに長文が打てるようになり、キーボードの使い方も様になってきたと思います。
盛り上がり: 今日はアレンジ大賞のコメントを伝えたら、すこしご満悦になっていました。お母さんが伝え忘れていたこともあり、余計嬉しかったみたいです。'),
  ('014b6baf-9dc4-5d49-ad34-100fc18736b0', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '16:30:00', null, '通常 / ジャンプゲーム基本操作09がちょうどおわっったところなので、チュートリアルあるくんの冒険https://app.arspark.jp/contents/3050 を最初から作成してみる→台にのれるようにするにはどうしたらいいか？を細かく教えていきたい', 'ジャンプの基本が終わったので、再度おさらいから。 Y座標を何回繰り返すのコードを使うのはどうしてなのか？を理解した上で、地面にめり込むバグを説明 地面からジャンプするためには、色とスプライトからのやり方二つあるとの説明とともに、地面の部分に触れていない時は下がるということを理解しました。 チュートリアル２もちゃんと自分でみないでも自分で完成するところまで（しかもクリアまで）出来上がっていました。', null, '盛り上がり: ゲームをしていくことに対しての抵抗感がなく、またいろいろな細かいコードの知識が増えることに楽しみを感じている様子です！'),
  ('f4010817-6d2c-57d2-ac0a-541a55e9368f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-15', '17:30:00', null, '通常 / あるくんチュートリアルジャンプ②を以前やっていたので、そのジャンプで土台にめり込まないようにするために（https://app.arspark.jp/projects/22024/editor） →あるくんジャンプ③の土台がいくつかあるVerを最初から作成してみるの部分までやってみる', '土台にめり込まないようにするためにの話を最初に説明。 やり方はスプライトに触れたら〜と色に触れたら〜のどちらかで大丈夫だという話と、デメリットもあることを説明しました。 その上でチュートリアルあるくんジャンプ③を自分で最初から組み立てられるか？を行なってみました。 今日は最初の30分ほどは良かったのですが、残り30分はずっと居眠りをしていて、何回かお水を飲みに行ってもらったり、すこし体を動かしたり休憩時間を入れながら行いました。 最後は自分でジャンプのコードまではかけていたので、次回は完成まで進めていきたいと思います。', null, 'タイピング: タイピングもだいぶ慣れてきて、タイピングだけでも時間をかけて練習できるようになりました。
盛り上がり: めり込まない→触れたところからジャンプするという意味にするんだよと伝えた時に、なるほど！という理解が感じられました。'),
  ('4d0ee94e-dc36-5be8-94f0-d33d41f9291a', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-05-15', '18:40:00', null, '休み（未対象）', null, null, null),
  ('5852fec5-2286-50e2-9c57-ee3af23e1ef6', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '3d62819a-addc-5584-afc3-251fdb7abc04', '2023-05-13', '17:30:00', null, '通常 / 【DKゲーム】02迷路チーズをさがせ！ 素材だけ ヒント付き', '素材だけの02迷路チーズをさがせ！ の作製に取り組みました。 自己流でScratchでゲームなどを作っていた経験があるということで「自分で考えて、問題を解決する能力は高い」のですが、基礎的なところが身についていなかったり自己流だったりするところが散見されるので要注意です。 次回からは「写経中心が良い」と思います。 自分で考える地力のある子なので「写経→スクリプトを読み解く」というプロセスを繰り返して実力をつければすごく伸びると思います。 ただ、教えてもらうのはそんなに好きではなさそうなので、「スクリプトを読み解く」のほうは無理にしなくてもいいかもしれません。 ただ「写経は必須」だと思いますので次回からお願いします。', '必ず「写経」をお願いします。 なるべく難易度の低いものから始めるほうが良いと思います。 地力があるので複数の課題を用意しておいたほうが良いです。 本人が嫌がらなければ本人に「スクリプトの意味を読み解いて理解する」プロセスがあるといいと思います。イヤそうならしなくていいと思いますが「写経」は必須です。', 'タイピング: 不明
盛り上がり: 自分で考えてブロックを組むのが好きなようです。 自分で考えてトライ＆エラーができます。
備考: 次回指導のターニングポイントだと思うのでよろしくお願いします。'),
  ('0605c7a9-36f8-51e1-abe2-e05c48207cff', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-13', null, null, '通常 / リストを使ったゲームの細分化、リストと多要素との連携の学習', 'リストを使いこなす練習としておばけのかくれんぼに取り組みましたが、予想よりも早く終わりました。座標をリストにするというヒントを出すと、「x座標をリストの[乱数]番目にする」というブロックをすぐに作れました。その後[乱数]をもう一度使う必要があることがわかり困っていたのですが、変数に[乱数]を格納することで解決しました。本題のリストよりも他の場所のほうが大変だったと思います。', '都道府県と県庁所在地クイズ(リストの応用)', '時間帯: その他'),
  ('5906d8a6-1e4c-527a-bb9b-98c33957b1dc', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-05-13', null, null, '通常 / ビルのゲームの完成', 'ビルのゲームが途中だったので続きをやりました。最初はビルをクローンとして出すコードを書きました。クローンは一度だけやったことがあるとのことでしたが、あまり慣れてはいない様子で、クローンの動作を作っているつもりで本体の動作を作っていたりしました。そのため、クローンの動作は「クローンされたとき」のブロックにつなげて作ろうという話をしました。その後、鳥がビルを通り抜けた数を変数としてカウントするのをやりました。変数を加算する条件として「x座標=○○なら」を使っていたので、考え方は合っているけどぴったりその座標を通過するとは限らないということで「x座標<○○なら」というやり方なら確実だと伝えました。 30分くらい余ったので好きな小技を選んでやってもらいました。前半と同じくクローンを使う内容だったのでアウトプットをしてもらおうと思い、できるところまでは自力でやってもらい、クローンの生成をすることができました。最後までは難しかったようなので写経で完成させました。', null, '時間帯: その他
タイピング: まじめにやっていました。
盛り上がり: ゲームが完成したときは達成感を感じたようでした。'),
  ('1c74ee94-81b0-5a68-91d9-c700339dde16', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / 教室、授業に慣れる', '30分以上前に入室していて、授業開始直前に思うようなゲームで遊べなかったせいか、少し疲れた様子を見せていたので、授業を楽しんでもらうことを最優先に進めました。 「アイスを食べに」に興味を示したのですが、チュートリアルへの反応がイマイチだったので、サムネイルを見ながら「どんなゲームにしたらおもしろいか」を考えて一緒に形にしていきました。 ゲーム仕様についてはしっかりと「こういうふうにしたい」と話してくれたので、のあくんの要望に合わせてブロックを教えていきました。 「～へ向ける」「動かす」「表示する」「隠す」「メッセージの送信と受信」「スタート時の座標」「〇秒でどこかの場所へいく」「もしスプライトに触れたなら」「終わるまで音を鳴らす」の学習ができました。 今日学んだスキルのところにスタンプを押して、次回以降、表をうめていくという説明をして納得していました。', null, '時間帯: その他
タイピング: アルファベットは余裕で読めていてキーの位置もなんとなくわかっているようでしたが、今日はまだやりたくない、とのことでした
盛り上がり: 30分ほどで、のあくん流「アイスを食べに」が完成して、満足そうでした。お母さんに見せることをとても楽しみにしていて、お迎えの際に嬉しそうに説明していました。 2つのレースゲームで遊びながら、ゲームを簡単にするという名目で乱数や変数の数値の変更をやりましたが、それをとても楽しんでくれました。
備考: スパイダーマンが大好きだそうです。'),
  ('c2cfac1b-e56b-5af8-873b-65167fcc1a5f', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / スプライトの向きと条件分岐の学習', '前回疲れと飽きが見られたようなので、今日は敢えてあおしくんと同じ課題に取り組んでもらいました。条件分岐を使用した基本的なゲームの作成には慣れてきたようです。 タッチするスプライトの中にボスキャラを作ったりと、コスチュームや音を工夫して楽しそうにアレンジしていました。 複数の動作を無理に一つのスクリプトにつなげていて思う通りに動かなかったため、伊藤さんが並列処理を教えてくれました。', 'アレンジの完成', '時間帯: その他
タイピング: サクサクと済ませていました
盛り上がり: 今日のゲームのアレンジは楽しかったようで、終盤「疲れた」とは言っていましたが、最後まで飽きずに取り組んでいました。 あおしくんとは、お互いとても良い刺激になっているようで、切磋琢磨しながら盛り上がっていました。'),
  ('d96cd5ff-c05e-5c84-bfa2-4be7d711b126', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, null, '2023-05-13', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('4e772489-b275-5301-84b6-43aaa3d9af6c', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, null, '2023-05-13', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('15f87b02-da40-5510-81ac-977a111c51f7', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-05-13', null, null, '通常 / 条件分岐の学習とゲームアレンジの楽しさの学習', '課題の範囲の作成は、ほぼノーヒントですぐにできていました。 こちらが敢えてヒントを出さなかった、ゲーム開始時のスプライト表示や条件分岐の際のずっとブロックなども、自主的に追加することができていました。 時間オーバーするまで、一生懸命にアレンジをしていました。アレンジ大賞以来、自主的にアイディアを出してそれを自分で形にしようとする力が伸びたように思えます。', 'アレンジの完成', '時間帯: その他
タイピング: ミスが0%になるようにこだわっていました
盛り上がり: 今日からそうたくんが同じ時間になったせいか、授業開始時やタイピングからプログラミングへの切り替えもとても素早くなりました。 途中でだれることもなく、アレンジを一生懸命考えて楽しそうに作成していました。'),
  ('fa76f948-4395-57c4-b358-37757c92f79f', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '18:40:00', null, '通常 / りんごキャッチゲーム1（リンゴの落ちてくる動作など）', '見本で遊んでもらったあと、チュートリアルを見ながら取り組むように進めましたが、ほぼ自力で取り組んでいました。世界観を大事にしていて、落ちてくるカプセル、キャッチする人間の他にも白熊を置いたりウサギを動かしたりして、冬のキャッチゲームを演出していました。 カプセルの落ちてくるプログラムも自分で作れていました。少しカクカク動いていたので、チュートリアルを一緒に見ながら確認しました。動画通りにプログラムするとカプセルの向きがひっくりかえってしまったのですが、「回転しない」を自分でしっかりプログラムできていました。', '仕上げです！', 'タイピング: ミス率もすくなく、集中して取り組めていました。
盛り上がり: とても集中して取り組んでいました！'),
  ('2ef8b22e-77c7-546b-acc0-8cb8511f084c', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '17:30:00', null, '通常 / 日が空いているので一番最初からもう一度確認、右左上下のキーで動かすのはもちろんのこと条件分岐で矢印の方向に動く', '本当はジャンプ＋敵が出てくるの部分＞条件分岐で矢印の方向に動くまでやりたかったのですが、ジャンプと敵がでてくる部分で終了。ちょっとお疲れモードのかんじで（遠足だったため）またGW明けというのもありコード自体を結構忘れている感じでした。', null, 'タイピング: 同じを見つけるのがまだ難しいみたい、学校でもやり始めたのもあるので頑張っていました
盛り上がり: やっていること自体はとても楽しそうで、他のことも楽しくやっていました。'),
  ('6f4ebb40-0bee-50f5-8f1e-f9917d4d8731', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '17:30:00', null, '通常 / 弾幕シューティング（角度、クローン）', '久しぶりにこちらからリクエストしたことをやってくれました！！！回転させたり、クローンを自分から作ったりできていました。回転させるスプライトの見た目に注目し、自分なりに工夫していました。回転速度について質問しましたが、あまりこだわりがないようです。 クローンされた後の動きの作り方を少し忘れてしまっていたようです。親分と子分の考え方を強調して説明しました。クローンされた後の削除も伝えました。 今日は特に楽しく取り組めていました！この調子でいきたいです。', null, null),
  ('a3eb72ab-1908-5a6a-9458-426a3dea1f83', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '17:30:00', null, '通常 / 変数の目印としての役目 ジャンプのプログラムで「飛ぶ」= 0 なのはなぜ？？', 'マリオのジャンプのプログラムに注目してもらい、「飛ぶ」の変数の役割に注目しました。すぐには気づけなかったようなので、マリオ全体のプログラムをみるように促しました。「地面にいるとき」とそうでないときとで区別されていることを一緒に確認しました。 その後、ジャンプにフォーカスし、地面の認識の話をしました。地面に落ちるまで下がり続けるということはすぐに納得がいったようです。ジャンプの上がるときは定数で一気に上げましたが、下がるときは重力も考えて「～まで繰り返す」を使ってうまくプログラムを作ることができました。背景やスプライトに自分なりに工夫をつけられていました！すごい！！', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 優勝で嬉しそうでした！！良かったです！！'),
  ('448393bd-af93-5783-a523-78cd63093078', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '18:40:00', null, '通常 / 前回基本操作コース09が途中、ジャンプは問題なさそうなのであとは敵が動くのを追加してスコアの部分を作成する', 'ちゃんとジャンプを作る問題自体は覚えていた様子、GW明けでもコードの内容自体は覚えていたので、途中の部分からでもスラスラと書いていました。 敵のコード自体も問題なく右から左に動くなどもできていたので、チュートリアルのアドバンスの方でフリエを助けろをやってもらいました 応用としてだったので、すでにコードが書いてあるのを手直しという感じだったのもあるので早々に終了。 多少やっつけな感じはありましたが、久しぶりの授業だったので、最後は早めに退出となりました', '今度は今日やったチュートリアルのバグっぽい部分の修正をしていきたいと思います', 'タイピング: なし
盛り上がり: ちゃんと自分が描いていたもの自体を覚えていたのがすごい！'),
  ('dcf668cf-6b10-5ccd-988e-e3c7ba2855c3', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-05-12', '18:40:00', null, '通常 / （前回の続き）ジャンプの謎の部分を解決 変数と乱数を組み合わせて空飛ぶブロックを追加など', '前回作った作品のジャンプの部分を一緒に見直しました。地面のスプライトを別に作って、地面にめり込まないジャンプのプログラムを一緒に目指しました。ポイントとして、「上昇」と「下降」を別々に考え、さらに空中にいってしまったときに重力を考えることを提案しました。 うまくいっていないときも自分なりにプログラムを解釈して、うまくいかない原因を探せていたのでとても良かったです。最終的にきちんとジャンプさせることはできませんでしたが（スライムのなかにめり込んでしまう形になりました）、いろいろなジャンプのさせ方を検討したので、技が増えたのではないかと思います。', null, 'タイピング: ややミスタイプが多かったです。'),
  ('f1bd5056-8598-5f34-8d89-44cfe4decde5', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '16:30:00', null, '通常 / スタートを受け取った時～という命令以外に旗が押されたら～という条件分岐で全ての命令が、できるようにするほうに移行する方がいいのかな？メッセージの多用自体は悪くないがどこのメッセージなのか？がわかりにくくなってしまう？ →メッセージの名前をわかりやすいものに変えることを最初に伝えてあげる', 'メッセージの送り合いすぎでわかりにくくなってしまった感じがあったので、メッセージのきちんとした名前の付け方がどうして必要なのか？の話から、条件分岐でもちゃんと変数と組んでやればメッセージを送らなくてもできることを理解しました。 また変数でも、全体のスプライトに適用なのか、個々のスプライト用なのか？の違いまで含めて案内。 その上で今回は、アレンジ大賞で作っていたもので条件分岐に再度トライ。 点数で背景が変わるというコードを変数と演算、条件分岐で組んでもらいました（もちろん背景は全体変数しか選べないことも伝えすみで）', null, 'タイピング: なし
盛り上がり: 条件分岐が重ねるという部分がまだ難しくなる話をしていたら、そのコードも書いてみたい！となっていたので、次は変数の目印もし〜でなければ〜の重ねるをしていこうと思います。'),
  ('fc1a2eb0-c4ae-5c25-8de3-d7d5fef3524c', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-05-12', '16:30:00', null, '通常 / 前回正方形を書くという部分で止まっているので、再度復習し、繰り返すというコードを使って同じように描けないか？を話す（アレンジ大賞の件もあるので） 終わったら三角形→五角形にチャレンジ！', 'アレンジ大賞の件で最初にどの部分がバグになってしまっていたのか？を確認。繰り返しという部分がなんとなく〜の理解だったため、図形の問題で何回繰り返すのか？の何回の部分を自分で確認してもらいました（画数が増えるとその分何回繰り返すというのも理解してもらいました） 360度の問題で円を描き、ジャンプの問題も再度確認してもらいました→どうして何回繰り返すを使うのかまでを理解したように思います。', null, 'タイピング: なし
盛り上がり: 算数には抵抗がない様子で、円を5個書いてオリンピックふうに書いてみるというのがとても楽しそうに描いていました。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
